  9→export default function SignInForm({ retrieveDatabase, setLoggedIn }) {
 10→  const [formValue, setFormValue] = useState({ email: "", password: "" });
 11→  const [errorValue, setErrorValue] = useState({});
 12→  const [loading, setLoading] = useState(false);
 13→  const [retrievedUser, setRetrievedUser] = useState(true);
 14→  const [captchaError, setCaptchaError] = useState(false);
 15→  const navigate = useNavigate();
 16→  const captchaRef = useRef();
 17→
 18→  const submitForm = async (e) => {
 19→    e.preventDefault();
 20→    setLoading(true);
 21→    //validate form before sending to server
 22→    setErrorValue(validateForm(formValue));
 23→    //if error object isn't empty stop the process
 24→    if (Object.keys(validateForm(formValue)).length > 0) {
 25→      setLoading(false);
 26→      return null;
 27→    }
 28→    //otherwise check if user registration on the server returns OK and reset the form
 29→    else {
 30→      let captchaToken = captchaRef.current?.getValue();
 31→      if (captchaToken.length === 0) {
 32→        setCaptchaError("ReCaptcha is mandatory");
 33→        setLoading(false);
 34→        return;
 35→      }
 36→      window.scrollTo(0, 0);
 37→      const verify = await verifyCaptcha(captchaToken);
 38→
 39→      if (verify) {
 40→        try {
 41→          const retrievedUserOK = await retrieveDatabase(
 42→            formValue.email.toLowerCase(),
 43→            formValue.password
 44→          );
 45→
 46→          if (retrievedUserOK === false) {
 47→            setRetrievedUser(false);
 48→            setFormValue({ email: "", password: "" });
 49→          } else {
 50→            navigate(`/profile`);
 51→            setLoading(false);
 52→            window.scrollTo(0, 0);
 53→            setRetrievedUser(true);
 54→            setFormValue({ email: "", password: "" });
 55→            setLoggedIn(true);
 56→          }
 57→        } catch (error) {
 58→          console.error("Error during user retrieval:", error);
 59→        } finally {
 60→          setLoading(false);
 61→        }
 62→      } else {
 63→        captchaRef.current?.reset();
 64→        setLoggedIn(false);
 65→        setFormValue({
 66→          firstname: "",
 67→          lastname: "",
 68→          email: "",
 69→          message: "",
 70→        });
 71→        setCaptchaError("");
 72→        setLoading(false);
 73→      }
 74→    }
 75→  };
 76→
 77→  const handleChange = (e) => {
 78→    const { name, value } = e.target;
 79→    setFormValue({ ...formValue, [name]: value });
 80→  };
 81→  const verifyCaptcha = async (captchaToken) => {
 82→    try {
